SELECT dungeon_name, AVG(dungeon_rating) AS avg_rating
FROM dungeons
GROUP BY dungeon_name;

SELECT COUNT(*) 
FROM dungeons 
WHERE min_level <= 100 AND max_level >= 110;

SELECT region_id, COUNT(realm_id) AS number_of_realms
FROM realms
GROUP BY region_id;

SELECT player_id, COUNT(achievement_id) AS achievement_count
FROM player_achievements
GROUP BY player_id;

SELECT dungeon_name
FROM dungeons
ORDER BY dungeon_popularity DESC;

SELECT dungeon_name, dungeon_rating_count
FROM dungeons
WHERE dungeon_rating_count = (SELECT MAX(dungeon_rating_count) FROM dungeons);

SELECT character_name
FROM player_characters
WHERE character_gear_score > 2000;

SELECT COUNT(*) 
FROM dungeon_tips 
WHERE tip_status = 'approved';

SELECT dungeon_name, (min_level + max_level) / 2 AS avg_level
FROM dungeons
ORDER BY avg_level DESC;
